public interface ShippingStrategy {
    double calculateCost(double weight, double distance);
}

class StandardShipping implements ShippingStrategy {
    public double calculateCost(double weight, double distance) {
        return 0.5 * weight * distance;
    }
}

class ExpressShipping implements ShippingStrategy {
    public double calculateCost(double weight, double distance) {
        return 1.5 * weight * distance + 10.0;
    }
}

class SameDayShipping implements ShippingStrategy {
    public double calculateCost(double weight, double distance) {
        return 3.0 * weight * distance + 25.0;
    }
}

class ShippingContext {
    private ShippingStrategy strategy;
    public void setStrategy(ShippingStrategy s) { this.strategy = s; }
    public double calculate(double weight, double distance) {
        return strategy.calculateCost(weight, distance);
    }
    public static void main(String[] args) {
        ShippingContext ctx = new ShippingContext();
        ctx.setStrategy(new StandardShipping());
        System.out.println("Standard: $" + ctx.calculate(2.0, 100.0));
        ctx.setStrategy(new ExpressShipping());
        System.out.println("Express: $" + ctx.calculate(2.0, 100.0));
        ctx.setStrategy(new SameDayShipping());
        System.out.println("Same Day: $" + ctx.calculate(2.0, 100.0));
    }
}

