#include <iostream>
#include <string>
#include <unordered_map>
#include <memory>
#include <climits>
using namespace std;

struct CacheEntry { string value; int frequency; int lastAccessed; int insertOrder; };

class EvictionStrategy {
public:
    virtual ~EvictionStrategy() = default;
    virtual string selectEviction(const unordered_map<string, CacheEntry>& entries) = 0;
};

class LRUEviction : public EvictionStrategy {
public:
    string selectEviction(const unordered_map<string, CacheEntry>& entries) override {
        string key; int minTime = INT_MAX;
        for (const auto& [k, e] : entries)
            if (e.lastAccessed < minTime) { minTime = e.lastAccessed; key = k; }
        return key;
    }
};

class Cache {
private:
    int maxSize, clock = 0, insertCounter = 0;
    unordered_map<string, CacheEntry> store;
    unique_ptr<EvictionStrategy> strategy;
public:
    Cache(int size, unique_ptr<EvictionStrategy> s) : maxSize(size), strategy(std::move(s)) {}
    void put(const string& key, const string& value) {
        if (store.count(key)) { store[key].value = value; return; }
        if ((int)store.size() >= maxSize) {
            string evict = strategy->selectEviction(store);
            store.erase(evict);
        }
        store[key] = {value, 1, ++clock, ++insertCounter};
    }
};
